//! Standalone `lua-rs` interpreter — minimal entry point that exercises the
//! full pipeline: `new_state` → `open_libs` → `load_string` → `pcall_k`.
//!
//! This is intentionally minimal — its job is to surface which `todo!()`
//! stubs block real execution, NOT to be a complete Lua interpreter.
//!
//! Usage:
//!   lua-rs '<lua source>'
//! Examples:
//!   lua-rs 'print("hello")'
//!   lua-rs '1+1'

use std::panic::{catch_unwind, AssertUnwindSafe};
use std::process::ExitCode;

use lua_stdlib::auxlib::load_string;
use lua_stdlib::init::open_libs;
use lua_types::closure::LuaLClosure;
use lua_types::error::LuaError;
use lua_types::gc::GcRef;
use lua_types::upval::UpVal;
use lua_types::value::LuaValue;
use lua_vm::api::{pcall_k, to_lua_string};
use lua_vm::state::{new_state, LuaState};

fn parser_hook(
    state: &mut LuaState,
    source: &[u8],
    name: &[u8],
    firstchar: i32,
) -> Result<GcRef<LuaLClosure>, LuaError> {
    let proto = lua_parse::parse(
        state,
        lua_parse::DynData::default(),
        source,
        name,
        firstchar,
    )?;
    let nupvals = proto.upvalues.len();
    let mut upvals = Vec::with_capacity(nupvals);
    for _ in 0..nupvals {
        upvals.push(GcRef::new(UpVal::Closed(LuaValue::Nil)));
    }
    Ok(GcRef::new(LuaLClosure {
        proto: GcRef::new(*proto),
        upvals,
    }))
}

const MULTRET: i32 = -1;

fn render_lua_error(e: &LuaError) -> String {
    match e {
        LuaError::Runtime(v) | LuaError::Syntax(v) => match v {
            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
            other => format!("{}: {:?}", e_tag(e), other),
        },
        LuaError::Memory | LuaError::Error | LuaError::Yield
        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
    }
}

fn e_tag(e: &LuaError) -> &'static str {
    match e {
        LuaError::Runtime(_) => "Runtime",
        LuaError::Syntax(_)  => "Syntax",
        LuaError::Memory     => "Memory",
        LuaError::Error      => "Error",
        LuaError::Yield      => "Yield",
        LuaError::File       => "File",
        LuaError::Gc         => "Gc",
    }
}

fn main() -> ExitCode {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("usage: {} '<lua source>'", args[0]);
        eprintln!("example: {} 'print(\"hello\")'", args[0]);
        return ExitCode::from(2);
    }
    let source = args[1].as_bytes().to_vec();

    eprintln!("[1/4] Creating LuaState...");
    let result = catch_unwind(AssertUnwindSafe(|| {
        let mut state = new_state().ok_or("new_state returned None")?;
        state.global_mut().parser_hook = Some(parser_hook);

        eprintln!("[2/4] Opening standard library...");
        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;

        eprintln!("[3/4] Loading source (parse + compile)...");
        let status = load_string(&mut state, &source)
            .map_err(|e| format!("load_string failed: {}", render_lua_error(&e)))?;
        if status != 0 {
            let msg = match to_lua_string(&mut state, -1) {
                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
                _ => "(no error message on stack)".to_string(),
            };
            return Err(format!(
                "Syntax: {} (load_string status={})",
                msg, status
            ));
        }

        eprintln!("[4/4] Executing chunk...");
        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;

        Ok::<_, String>(final_status)
    }));

    match result {
        Ok(Ok(status)) => {
            eprintln!("[ok] execution completed, status={:?}", status);
            ExitCode::SUCCESS
        }
        Ok(Err(msg)) => {
            eprintln!("[err] {}", msg);
            ExitCode::from(1)
        }
        Err(panic) => {
            let msg = if let Some(s) = panic.downcast_ref::<String>() {
                s.clone()
            } else if let Some(s) = panic.downcast_ref::<&str>() {
                s.to_string()
            } else {
                "(non-string panic payload)".to_string()
            };
            eprintln!("[panic] {}", msg);
            ExitCode::from(101)
        }
    }
}

// ──────────────────────────────────────────────────────────────────────────
// PORT STATUS
//   source:        (minimal entrypoint; not a port of lua.c — that's Phase F)
//   target_crate:  lua-cli
//   confidence:    high
//   todos:         0
//   port_notes:    0
//   unsafe_blocks: 0
//   notes:         drives new_state → open_libs → load_string → pcall_k.
//                  Designed to surface the first todo!() panic on a hello-
//                  world program, not to be a complete interpreter.
// ──────────────────────────────────────────────────────────────────────────

/// C: LClosure *luaY_parser(lua_State *L, ZIO *z, Mbuffer *buff, Dyndata *dyd,
///                           const char *name, int firstchar)
/// Top-level entry point: parses a chunk and returns the main LClosure.
/// LUAI_FUNC visibility.
///
/// PORT NOTE: In C, returns `LClosure *` (a GC object). In Rust (Phase A),
///   we return `Box<LuaProto>` since we don't have GcRef<LuaLClosure> ready.
///   Phase B will wrap this in a proper LuaLClosure / GcRef.
pub fn parse(
    state: &mut LuaState,
    dyd: DynData,
    source: &[u8],
    name: &[u8],
    firstchar: i32,
) -> Result<Box<LuaProto>, LuaError> {
    let source_str = state.intern_str(name)?;
    let envn_str = state.intern_str(lua_lex::LUA_ENV)?;

    let rest_bytes: Vec<u8> = source.iter().skip(1).copied().collect();
    let z = lua_lex::ZIO::from_bytes(rest_bytes);

    let lex_ls = lua_lex::LexState {
        current: firstchar,
        linenumber: 1,
        lastline: 1,
        t: lua_lex::Token::eos(),
        lookahead: lua_lex::Token::eos(),
        fs: None,
        z,
        buff: lua_lex::LexBuffer::new(),
        h: None,
        dyd: None,
        source: source_str.0.clone(),
        envn: envn_str.0.clone(),
    };

    let mut lexstate = LexState {
        current: lex_ls.current,
        linenumber: lex_ls.linenumber,
        lastline: lex_ls.lastline,
        t: LexToken::default(),
        lookahead: LexToken::default(),
        fs: None,
        dyd,
        source: Some(source_str.clone()),
        envn: Some(GcRef(lex_ls.envn.clone())),
        lex: lex_ls,
    };
    // C: luaX_setinput is the only setup the C parser performs before
    //   `mainfunc`; it does NOT pre-read the first token. `mainfunc` itself
    //   issues the initial `luaX_next` once its prelude (open_func, vararg
    //   marker, _ENV upvalue) is in place.

    let mut main_proto = Box::new(LuaProto::placeholder());
    main_proto.source = Some(source_str);
    main_proto.is_vararg = true;
    let main_fs = FuncState {
        f: main_proto,
        prev: None,
        bl: None,
        pc: 0,
        lasttarget: 0,
        previousline: 0,
        nk: 0,
        np: 0,
        nabslineinfo: 0,
        firstlocal: 0,
        firstlabel: 0,
        ndebugvars: 0,
        nactvar: 0,
        nups: 0,
        freereg: 0,
        iwthabs: 0,
        needclose: false,
    };

    mainfunc(&mut lexstate, state, main_fs)
}

/// Convert a `lua_lex::TokenValue` into the local `parse::TokenValue` flat shape.
///
/// The parser's local `LexState` predates the lex-side enum and uses a flat
/// (r, i, ts) record; this picks out whichever variant the lexer produced.
fn local_token_value(v: &lua_lex::TokenValue) -> TokenValue {
    match v {
        lua_lex::TokenValue::None => TokenValue::default(),
        lua_lex::TokenValue::Float(r) => TokenValue { r: *r, i: 0, ts: None },
        lua_lex::TokenValue::Int(i) => TokenValue { r: 0.0, i: *i, ts: None },
        lua_lex::TokenValue::Str(s) => TokenValue { r: 0.0, i: 0, ts: Some(GcRef(s.clone())) },
    }
}

