2611	fn exprstat(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
2612	    let mut v_assign = LhsAssign { prev: None, v: ExprDesc::default() };
2613	    suffixedexp(ls, state, &mut v_assign.v)?;
2614	    if ls.t.token == b'=' as TokenKind || ls.t.token == b',' as TokenKind {
2615	        // C: stat -> assignment
2616	        restassign(ls, state, &mut v_assign, 1)?;
2617	    } else {
2618	        // C: stat -> func call; check it's a call, fix result count
2619	        if v_assign.v.k != ExprKind::Call {
2620	            return Err(LuaError::syntax(format_args!("syntax error")));
2621	        }
2622	        // C: SETARG_C(*inst, 1) — call statement uses no results
2623	        // TODO(port): fix instruction to set C=1 (no results)
2624	        let info = v_assign.v.u.info as usize;
2625	        // TODO(port): ls.fs.as_mut().unwrap().f.code[info].set_arg_c(1);
2626	    }
2627	    Ok(())
2628	}
