2630	/// C: static void retstat(LexState *ls)
2631	fn retstat(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
2632	    let first = {
2633	        let fs = ls.fs.as_ref().unwrap();
2634	        nvarstack(ls, fs)
2635	    };
2636	    let nret: i32;
2637	    if block_follow(ls, true) || ls.t.token == b';' as TokenKind {
2638	        nret = 0;
2639	    } else {
2640	        let mut e = ExprDesc::default();
2641	        nret = explist(ls, state, &mut e)?;
2642	        if e.k.has_mult_ret() {
2643	            // C: luaK_setmultret(fs, &e)
2644	            // TODO(port): lua_code::set_returns(ls.fs.as_mut().unwrap(), &mut e, LUA_MULTRET)?;
2645	            if e.k == ExprKind::Call && nret == 1 {
2646	                // C: tail call check — !fs->bl->insidetbc
2647	                let insidetbc = ls.fs.as_ref().unwrap().bl.as_ref().map_or(false, |b| b.insidetbc);
2648	                if !insidetbc {
2649	                    // C: SET_OPCODE(getinstruction(fs, &e), OP_TAILCALL)
2650	                    let info = e.u.info as usize;
2651	                    // TODO(port): ls.fs.as_mut().unwrap().f.code[info].set_opcode(OpCode::TailCall);
2652	                }
2653	            }
2654	            // nret = LUA_MULTRET handled by set_returns
2655	        } else {
2656	            if nret == 1 {
2657	                // C: first = luaK_exp2anyreg(fs, &e)
2658	                // TODO(port): let first = lua_code::exp_to_any_reg(ls.fs.as_mut().unwrap(), &mut e)?;
2659	            } else {
2660	                // TODO(port): lua_code::exp_to_next_reg(ls.fs.as_mut().unwrap(), &mut e)?;
2661	            }
2662	        }
2663	    }
2664	    // C: luaK_ret(fs, first, nret)
2665	    // TODO(port): lua_code::emit_return(ls.fs.as_mut().unwrap(), first, nret)?;
2666	    // C: testnext(ls, ';')
2667	    test_next(ls, state, b';' as TokenKind)?;
2668	    Ok(())
2669	}
