2672	/// Top-level statement dispatcher.
2673	fn statement(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
2674	    let line = ls.linenumber;
2675	    // C: enterlevel(ls)
2676	    // TODO(port): state.inc_c_calls()?;
2677	    match ls.t.token {
2678	        c if c == b';' as TokenKind => {
2679	            lex_next(ls, state)?;
2680	        }
2681	        TK_IF => {
2682	            ifstat(ls, state, line)?;
2683	        }
2684	        TK_WHILE => {
2685	            whilestat(ls, state, line)?;
2686	        }
2687	        TK_DO => {
2688	            lex_next(ls, state)?; // skip DO
2689	            block(ls, state)?;
2690	            check_match(ls, state, TK_END, TK_DO, line)?;
2691	        }
2692	        TK_FOR => {
2693	            forstat(ls, state, line)?;
2694	        }
2695	        TK_REPEAT => {
2696	            repeatstat(ls, state, line)?;
2697	        }
2698	        TK_FUNCTION => {
2699	            funcstat(ls, state, line)?;
2700	        }
2701	        TK_LOCAL => {
2702	            lex_next(ls, state)?; // skip LOCAL
2703	            if test_next(ls, state, TK_FUNCTION)? {
2704	                localfunc(ls, state)?;
2705	            } else {
2706	                localstat(ls, state)?;
2707	            }
2708	        }
2709	        TK_DBCOLON => {
2710	            lex_next(ls, state)?; // skip '::'
2711	            let name = str_check_name(ls, state)?;
2712	            labelstat(ls, state, name, line)?;
2713	        }
2714	        TK_RETURN => {
2715	            lex_next(ls, state)?; // skip RETURN
2716	            retstat(ls, state)?;
2717	        }
2718	        TK_BREAK => {
2719	            breakstat(ls, state)?;
2720	        }
2721	        TK_GOTO => {
2722	            lex_next(ls, state)?; // skip 'goto'
2723	            gotostat(ls, state)?;
2724	        }
2725	        _ => {
2726	            exprstat(ls, state)?;
2727	        }
2728	    }
2729	    debug_assert!(
2730	        ls.fs.as_ref().unwrap().f.maxstacksize >= ls.fs.as_ref().unwrap().freereg
2731	            && ls.fs.as_ref().unwrap().freereg as i32
2732	                >= nvarstack(ls, ls.fs.as_ref().unwrap())
2733	    );
2734	    let nv = nvarstack(ls, ls.fs.as_ref().unwrap());
2735	    ls.fs.as_mut().unwrap().freereg = nv as u8;
2736	    // C: leavelevel(ls)
2737	    // TODO(port): state.dec_c_calls();
2738	    Ok(())
2739	}
