2743	/// C: static void mainfunc(LexState *ls, FuncState *fs)
2744	/// Compiles the main chunk (always a vararg function with _ENV upvalue).
2745	fn mainfunc(ls: &mut LexState, state: &mut LuaState, main_fs: FuncState) -> Result<Box<LuaProto>, LuaError> {
2746	    // C: open_func(ls, fs, &bl)
2747	    open_func(ls, state, main_fs)?;
2748	
2749	    // C: setvararg(fs, 0) — main function is always vararg
