/// C: static void codename(LexState *ls, expdesc *e)
fn codename(ls: &mut LexState, state: &mut LuaState, e: &mut ExprDesc) -> Result<(), LuaError> {
    // C: codestring(e, str_checkname(ls));
    let name = str_check_name(ls, state)?;
    codestring(e, name);
    Ok(())
}

