//             setnilvalue(L->top++) }
//    goto ret;
OpCode::Return0 => {
    if state.hook_mask() != 0 {
        let ra = base + i.arg_a();
        state.set_top(ra);
        state.set_ci_savedpc(ci, pc);
        state.poscall(ci, 0)?;
