    } else {
        if e.k != ExprKind::Void {
            // TODO(port): lua_code::exp_to_next_reg(fs, e)?;
        }
        if needed > 0 {
            // TODO(port): lua_code::emit_nil(fs, fs.freereg as i32, needed)?;
        }
    }
    if needed > 0 {
        // TODO(port): lua_code::reserve_regs(fs, needed)?;
    } else {
        fs.freereg = (fs.freereg as i32 + needed) as u8;
    }
