/// C: static void setvararg(FuncState *fs, int nparams)
fn setvararg(fs: &mut FuncState, state: &mut LuaState, nparams: i32) -> Result<(), LuaError> {
    fs.f.is_vararg = true;
    // C: luaK_codeABC(fs, OP_VARARGPREP, nparams, 0, 0)
