    }
    adjust_local_vars(ls, state, 3)?; // control variables
    forbody(ls, state, base, line, 1, false)?;
    Ok(())
}

/// C: static void forlist(LexState *ls, TString *indexname)
fn forlist(
    ls: &mut LexState,
